94	export interface ClaimInput {
95	  items: { type: string; material?: string; enchantment?: number }[];
96	  incident: { cause: string; damages: { itemType: string; amount: number }[] };
97	}
98	
99	export interface ClaimResult {
100	  payout: number;
101	  // remainingCap is not yet exercised by any test; its behaviour is driven by
102	  // the "claim — cap" tests still to come, so it stays optional for now.
103	  remainingCap?: number;
104	}
105	
106	const DEDUCTIBLE = 100;
107	
108	const INSURANCE_VALUES: Record<string, number> = {
109	  sword: 1000,
110	  amulet: 600,
111	  staff: 800,
112	  potion: 400,
113	  rune: 250,
114	  moonstone: 250,
115	};
116	
117	const CAP_MULTIPLIER = 2;
118	
119	const HIGH_ENCHANTMENT_CLAIM_THRESHOLD = 8;
120	const HIGH_ENCHANTMENT_REIMBURSEMENT_RATE = 0.5;
121	
122	const hasHighEnchantment = (
123	  item: ClaimInput["items"][number] | undefined,
124	): boolean =>
125	  item?.enchantment !== undefined &&
126	  item.enchantment >= HIGH_ENCHANTMENT_CLAIM_THRESHOLD;
127	
128	// Reimbursement for a single damage, before the deductible is applied.
129	const reimbursementBeforeDeductible = (
130	  item: ClaimInput["items"][number] | undefined,
131	  damageAmount: number,
132	): number =>
133	  hasHighEnchantment(item)
134	    ? damageAmount * HIGH_ENCHANTMENT_REIMBURSEMENT_RATE
135	    : damageAmount;
136	
137	// The total payout is capped at a multiple of the unmodified insurance sum.
138	const payoutCap = (items: ClaimInput["items"]): number => {
139	  const insuranceSum = items.reduce(
140	    (total, item) => total + INSURANCE_VALUES[item.type],
141	    0,
142	  );
143	  return CAP_MULTIPLIER * insuranceSum;
144	};
145	
146	export function claim(input: ClaimInput): ClaimResult {
147	  const rawPayout = input.incident.damages.reduce((total, damage) => {
148	    const item = input.items.find((i) => i.type === damage.itemType);
149	    const reimbursed = reimbursementBeforeDeductible(item, damage.amount);
150	    return total + (reimbursed - DEDUCTIBLE);
151	  }, 0);
152	
153	  const payout = Math.min(rawPayout, payoutCap(input.items));
154	  return { payout };
155	}
